  3709 |   // else
  3710 |   //    Y =  WillWrap ? false : ((X binop C) pred C2)
  3711 |   // => Y = !WillWrap ?  ((X binop C) pred C2) : false
  3712 |   // => Y = !WillWrap && ((X binop C) pred C2)
